-- Populate asset_ref from video_location filename (e.g. '/path/to/3770096LAS.mp4' → '3770096LAS')
UPDATE public.assets
SET asset_ref = COALESCE(NULLIF(regexp_replace(video_location, '^.*/([^/]+)\.\w+$', '\1'), video_location), '')
WHERE video_location != '' AND video_location IS NOT NULL;
